select

from t_live_user_tier_config

    is_deleted = 0

        and id = #{id}


        and status = #{status}


        and tier_name like concat('%', #{tierName}, '%')


        and tier_value = #{tierValue}



    order by ${orderBy}


    order by tier_sort asc, tier_value asc


    limit #{pageNo}, #{pageSize}

